def beta_to_mask(b):
    res = []
    zeros = ["0" for i in range(64)]
    ones = ["1" for i in range(64)]
    for i in range(GFBITS):
        if b % 2 == 0:
            res.append(zeros)
        else:
            res.append(ones)
        b = b >> 1
    return res

def betas_to_mask(b0, b1):
    mask1 = beta_to_mask(b0)
    mask2 = beta_to_mask(b1)
    res = []
    for i in range(len(mask1)):
        res.append(mask1[i] + mask2[i])
    return res

