# ---------- Butterflies ----------

out_base_addr = 0x7fffffc37c60
out_num = 32
out_bits = 256
out_bytes = out_bits // 8
out_limbs_num = 2
out_limbs_bits = out_bits // out_limbs_num
out_limbs_bytes = out_limbs_bits // 8
total_evals = out_num * out_bits

irreducible_poly = "z**13 + z**4 + z**3 + z + 1"
z = Symbol('z')
F = FiniteExtension(PurePoly(z**13 + z**4 + z**3 + z + 1, modulus=2))
basis = [ F(z**i) for i in range(0, GFBITS) ]
bases = [ basis ]
degree = 12
level = 6

deg = degree
for i in range(level):
    basis = basis.copy()
    basis.pop(0)
    twist = F(basis[0]**2 + basis[0])
    twistinv = F(twist.inverse())
    if i == level - 1:
        twistinv = F(1)
    basis  = [F((basis[j]**2 + basis[j]) * twistinv) for j in range(deg)]
    bases.append(basis)
    deg -= 1

for basis in bases:
    elm = basis.pop(0)
    basis.append(elm)
    basis.reverse()

def ith_eval_num(basis, i):
    ps = []
    idx = 0
    while i > 0:
        if i % 2 == 1:
            ps.append(basis[idx])
        i = i // 2
        idx += 1
    return F(sum(ps))

# out:
# - out[0][ 0]: L0x7fffffc37c60, L0x7fffffc37c70
# - out[0][ 1]: L0x7fffffc37c80, L0x7fffffc37c90
