# from lsb to msb
def bits(size, n):
    bs = []
    while n > 0:
        bs.append(n % 2)
        n = n // 2
    while len(bs) < size:
        bs.append(0)
    return bs

def rev_bits(size, n):
    bs = bits(size, n)
    bs.reverse()
    return bs

def bits_to_int(bs):
    return int(''.join(map(str, bs)), 2)

# Get the low or high limb (depending on high) of out[i][b]
def addr_of_out(i, b, high=0):
    out_offset = i * GFBITS * out_bytes
    gfbits_offset = b * out_bytes
    limb_offset = 0x10 * high
    return out_base_addr + out_offset + gfbits_offset + limb_offset

def get_out_elm(out_idx, gfbit, high, i):
    out_limb = addr_of_out(out_idx, gfbit, high)
    return f"%L0x{out_limb:x}[{i:3d}]"

def cut_butterflies_levels(poly_prefix, pvar, lvl, ois, cut_id, provewith, polyadd=None):
    basis_idx = level - (min(6, lvl))
    basis = bases[basis_idx]
    poly_num = 2**basis_idx
    zi_num = 2**len(basis)
    pis = []
    for i in range(poly_num):
        pis.append(bits_to_int(bits(max(basis_idx, 1), i))) # bit reverse
    res = []
    out_idxs = []
    for oi in ois:
        out_idx = oi // out_bits
        out_pos = oi % out_bits
        high = out_pos // out_limbs_bits
        limb_pos = out_pos % out_limbs_bits
        if lvl == 0:
            zi = (limb_pos % 64) * 2 + (limb_pos // 64)
            pi = pis[out_idx * 2 + high]
        elif lvl == 1:
            zi = limb_pos * 2 + high
            pi = pis[out_idx]
        elif lvl >= 2:
            two_expn_lvl_m2 = 2**(min(6, lvl) - 2)
            two_expn_lvl_m1 = 2**(min(6, lvl) - 1)
            zi = (oi % (256*two_expn_lvl_m2)) * 2 + (out_idx % two_expn_lvl_m1) // two_expn_lvl_m2
            pi = pis[out_idx // two_expn_lvl_m1]
        out_idxs.append(out_idx)
        poly_mons = [get_out_elm(out_idx, gfbit, high, limb_pos) for gfbit in range(GFBITS)]
        poly1 = f"poly z [ {', '.join(poly_mons)} ]"
        poly_suffix = "" if lvl >= 6 else f"{pi:02d}"
        poly2 = f"{poly_prefix}{poly_suffix}"
        if polyadd != None:
            poly2 = f"({poly2} + {polyadd})"
        zn = ith_eval_num(basis, zi)
        pvar_mod = pvar if zi == 0 else f"{pvar} + {zn}"
        res.append(f"    eqmod\n      ({poly1})\n      {poly2}\n      [{pvar_mod}, {irreducible_poly}, 2]")
    return f"""# -------------------------------------------------------------------
# Cut #{cut_id}: level {lvl}: out[{out_idxs[0]}]-out[{out_idxs[-1]}]
# -------------------------------------------------------------------

cut
  and [
{',\n'.join(res)}
  ]{provewith}
  &&
  true;

# Cut #{cut_id + 1}
cut true && true;
"""

