# numbering bits in out[i][*]
out_ois = []
for i in range(out_num):
    out_ois.append([i * out_bits + j for j in range(out_bits)])

def print_level0_cuts():
    cut_id = 2
    print(f"{cut_butterflies_levels('F5', 'X5', 0, range(0, total_evals), cut_id, ' prove with [precondition]')}")

def print_level1_cuts():
    cut_id = 4
    for l1cut in range(0, 32, 2):
        ois = range(l1cut * out_bits, (l1cut + 2) * out_bits)
        print(f"{cut_butterflies_levels('G4', 'Y4', 1, ois, cut_id, ' prove with [precondition, cuts [2]]')}")
        cut_id += 2

def print_level2_cuts():
    cut_id = 36
    for l2cut in range(0, 32, 2):
        ois = range(l2cut * out_bits, (l2cut + 2) * out_bits)
        print(f"{cut_butterflies_levels('G3', 'Y3', 2, ois, cut_id, f' prove with [precondition, cuts [{cut_id - 32}]]')}")
        cut_id += 2

# each iteration: out[i], out[i+s]

def print_level3_cuts():
    level3_cut_id = 68
    s = 2
    for j in range(0, 32, 2*s):
        provewith = f' prove with [precondition, cuts [{level3_cut_id - 32}, {level3_cut_id - 30}]]'
        for k in range(j, j+s):
            ois = out_ois[k] + out_ois[k+s]
            print(f"{cut_butterflies_levels('G2', 'Y2', 3, ois, level3_cut_id, provewith)}")
            level3_cut_id += 2

def print_level4_cuts():
    level4_cut_id = 100
    s = 4
    for j in range(0, 32, 2*s):
        provewith_cutids = [level4_cut_id - 32, level4_cut_id - 28]
        for k in range(j, j+s):
            provewith = f' prove with [precondition, cuts {[c + (k%2)*2 for c in provewith_cutids]}]'
            ois = out_ois[k] + out_ois[k+s]
            print(f"{cut_butterflies_levels('G1', 'Y1', 4, ois, level4_cut_id, provewith)}")
            level4_cut_id += 2

