def print_level7_cuts():
    level6_cut_id = 164
    level7_cut_id = 196
    s = 16
    for i in range(0, 32):
        provewith_cutids = [level6_cut_id + (i%s)*2]
        provewith = f' prove with [cuts {provewith_cutids}]'
        ois = out_ois[i]
        print(f"{cut_butterflies_levels('F', 'X', 7, ois, level7_cut_id, provewith, polyadd='X**128')}")
        level7_cut_id += 2

def print_postcondition():
    poly_prefix='F'
    pvar='X'
    level7_cut_id = 196
    polyadd='X**128'
    lvl = 6
    basis_idx = 0
    basis = bases[basis_idx]
    poly_num = 2**basis_idx
    zi_num = 2**len(basis)
    pis = []
    for i in range(poly_num):
        pis.append(bits_to_int(bits(max(basis_idx, 1), i))) # bit reverse
    res = []
    for out_idx in range(0, out_num):
        eqmods = []
        for out_pos in range(0, out_bits):
            oi = out_idx * out_bits + out_pos
            high = out_pos // out_limbs_bits
            limb_pos = out_pos % out_limbs_bits
            zi = (oi % (256*(2**(lvl-2)))) * 2 + (out_idx % (2**(lvl-1))) // (2**(lvl-2))
            pi = pis[out_idx // (2**(lvl-1))]
            poly_mons = [get_out_elm(out_idx, gfbit, high, limb_pos) for gfbit in range(GFBITS)]
            poly1 = f"poly z [ {', '.join(poly_mons)} ]"
            poly_suffix = "" if lvl == 6 else f"{pi:02d}"
            poly2 = f"{poly_prefix}{poly_suffix}"
            if polyadd != None:
                poly2 = f"({poly2} + {polyadd})"
            zn = ith_eval_num(basis, zi)
            pvar_mod = pvar if zi == 0 else f"{pvar} + {zn}"
            eqmods.append(f"""    # {zi}
    eqmod\n      ({poly1})\n      {poly2}\n      [{pvar_mod}, {irreducible_poly}, 2]""")
        res.append(f"""  and [
{',\n'.join(eqmods)}
  ] prove with [cuts [{level7_cut_id + out_idx*2}]]"""
)
    print (f"""{{
{',\n'.join(res)}
  &&
  true
}}
""")

